class NonceManager:
    """Manages cryptographic nonces for signature verification."""

    @staticmethod
    def generate_nonce(address: str) -> str:
        """Generate a cryptographically secure nonce for an address."""
        address = to_checksum_address(address)
        nonce = secrets.token_hex(32)
        nonce_data = {
            'nonce': nonce,
            'created_at': time.time(),
            'address': address,
            'used': 'false'
        }

        if USE_REDIS:
            key = f"auth_nonce:{address}"
            redis_client.hmset(key, nonce_data)
            redis_client.expire(key, NONCE_EXPIRATION_SECONDS)
        else:
            _nonce_store[address] = {**nonce_data, 'used': False}

        return nonce

    @staticmethod
    def validate_and_consume_nonce(address: str, nonce: str) -> bool:
        """Validate a nonce and mark it as consumed (one-time use)."""
        address = to_checksum_address(address)

        if USE_REDIS:
            key = f"auth_nonce:{address}"
            stored_data = redis_client.hgetall(key)

            if not stored_data:
                logger.warning(f"No nonce found for address {address}")
                return False

            stored_nonce = stored_data.get(b'nonce', b'').decode('utf-8')
            created_at = float(stored_data.get(b'created_at', b'0'))
            used = stored_data.get(b'used', b'false').decode('utf-8')

            if used == 'true':
                logger.warning(f"Nonce already used for address {address}")
                return False

            if time.time() - created_at > NONCE_EXPIRATION_SECONDS:
                logger.warning(f"Nonce expired for address {address}")
                redis_client.delete(key)
                return False

            if not hmac.compare_digest(stored_nonce, nonce):
                logger.warning(f"Nonce mismatch for address {address}")
                return False

            # Mark as used and delete
            redis_client.delete(key)
            return True
        else:
            stored_data = _nonce_store.get(address)

            if not stored_data:
                logger.warning(f"No nonce found for address {address}")
                return False

            if stored_data.get('used', False):
                logger.warning(f"Nonce already used for address {address}")
                return False

            if time.time() - stored_data['created_at'] > NONCE_EXPIRATION_SECONDS:
                logger.warning(f"Nonce expired for address {address}")
                del _nonce_store[address]
                return False

            if not hmac.compare_digest(stored_data['nonce'], nonce):
                logger.warning(f"Nonce mismatch for address {address}")
                return False

            # Mark as used and remove
            del _nonce_store[address]
            return True


class SignatureVerifier:
    """Handles Ethereum signature verification with security checks."""

    # Known invalid/burn addresses that should not be allowed to authenticate
    BLOCKED_ADDRESSES = {
        '0x0000000000000000000000000000000000000000',
        '0x000000000000000000000000000000000000dEaD',
    }

    @staticmethod
    def build_sign_message(address: str, nonce: str, domain: str = "Web3Auth") -> str:
        """Build a standardized message for signing following EIP-4361 style."""
        timestamp = datetime.utcnow().isoformat()
        message = (
            f"{domain} wants you to sign in with your Ethereum account:\n"
            f"{address}\n\n"
            f"Sign this message to authenticate.\n\n"
            f"Nonce: {nonce}\n"
            f"Issued At: {timestamp}"
        )
        return message

    @staticmethod
    def verify_signature(message: str, signature: str, expected_address: str) -> bool:
        """
        Verify an Ethereum signature and ensure the recovered address matches.

        Security measures:
        - Uses encode_defunct for EIP-191 personal_sign standard
        - Constant-time comparison of addresses
        - Validates address format before comparison
        - Checks against blocked addresses
        """
        try:
            # Validate inputs
            if not message or not signature or not expected_address:
                logger.warning("Missing required parameters for signature verification")
                return False

            # Validate address format
            if not is_address(expected_address):
                logger.warning(f"Invalid Ethereum address format: {expected_address}")
                return False

            expected_address = to_checksum_address(expected_address)

            # Check blocked addresses
            if expected_address in SignatureVerifier.BLOCKED_ADDRESSES:
                logger.warning(f"Blocked address attempted authentication: {expected_address}")
                return False

            # Validate signature format (should be 65 bytes hex with 0x prefix)
            if not signature.startswith('0x'):
                logger.warning("Signature missing 0x prefix")
                return False

            sig_bytes = bytes.fromhex(signature[2:])
            if len(sig_bytes) != 65:
                logger.warning(f"Invalid signature length: {len(sig_bytes)} bytes")
                return False

            # Verify v value is valid (27 or 28, or 0 or 1)
            v = sig_bytes[64]
            if v not in (0, 1, 27, 28):
                logger.warning(f"Invalid signature v value: {v}")
                return False

            # Encode the message using EIP-191 standard
            encoded_message = encode_defunct(text=message)

            # Recover the address from the signature
            recovered_address = w3_auto.eth.account.recover_message(
                encoded_message,
                signature=signature
            )

            recovered_address = to_checksum_address(recovered_address)

            # Constant-time comparison to prevent timing attacks
            address_match = hmac.compare_digest(
                recovered_address.lower().encode('utf-8'),
                expected_address.lower().encode('utf-8')
            )

            if not address_match:
                logger.warning(
                    f"Signature verification failed: recovered {recovered_address}, "
                    f"expected {expected_address}"
                )
                return False

            logger.info(f"Signature verified successfully for address {expected_address}")
            return True

        except ValueError as e:
            logger.error(f"Value error during signature verification: {e}")
            return False
        except Exception as e:
            logger.error(f"Unexpected error during signature verification: {e}")
            return False


class TokenManager:
    """Manages JWT tokens for authenticated sessions."""

    @staticmethod
    def create_token(address: str) -> str:
        """Create a JWT token for an authenticated address."""
        now = datetime.utcnow()
        payload = {
            'sub': to_checksum_address(address),
            'iat': now,
            'exp': now + timedelta(hours=JWT_EXPIRATION_HOURS),
            'jti': secrets.token_hex(16),  # Unique token ID
            'type': 'access'
        }
        return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)

    @staticmethod
    def verify_token(token: str) -> Optional[Dict[str, Any]]:
        """Verify and decode a JWT token."""
        try:
            payload = jwt.decode(
                token,
                JWT_SECRET,
                algorithms=[JWT_ALGORITHM],
                options={
                    'require': ['sub', 'iat', 'exp', 'jti', 'type'],
                    'verify_exp': True,
                    'verify_iat': True,
                }
            )

            if payload.get('type') != 'access':
                logger.warning("Invalid token type")
                return None

            # Validate the address in the token
            address = payload.get('sub', '')
            if not is_address(address):
                logger.warning(f"Invalid address in token: {address}")
                return None

            return payload

        except jwt.ExpiredSignatureError:
            logger.warning("Token has expired")
            return None
        except jwt.InvalidTokenError as e:
            logger.warning(f"Invalid token: {e}")
            return None


def require_auth(f):
    """Decorator to require JWT authentication on endpoints."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')

        if not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid Authorization header'}), 401

        token = auth_header[7:]  # Remove 'Bearer ' prefix

        payload = TokenManager.verify_token(token)
        if not payload:
            return jsonify({'error': 'Invalid or expired token'}), 401

        request.user_address = payload['sub']
        request.token_payload = payload
        return f(*args, **kwargs)

    return decorated


