@app.route('/api/auth/nonce', methods=['POST'])
@limiter.limit("10 per minute")
def get_nonce():
    """
    Request a nonce for authentication.
    The client must provide their Ethereum address.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    address = data.get('address', '').strip()

    if not address:
        return jsonify({'error': 'Ethereum address is required'}), 400

    if not is_address(address):
        return jsonify({'error': 'Invalid Ethereum address format'}), 400

    address = to_checksum_address(address)

    if address in SignatureVerifier.BLOCKED_ADDRESSES:
        return jsonify({'error': 'Address is not allowed'}), 403

    nonce = NonceManager.generate_nonce(address)
    message = SignatureVerifier.build_sign_message(address, nonce)

    return jsonify({
        'address': address,
        'nonce': nonce,
        'message': message,
    }), 200


@app.route('/api/auth/verify', methods=['POST'])
@limiter.limit("5 per minute")
def verify_signature():
    """
    Verify a signed message and issue a JWT token.
    The client must provide the address, signature, message, and nonce.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    address = data.get('address', '').strip()
    signature = data.get('signature', '').strip()
    message = data.get('message', '').strip()
    nonce = data.get('nonce', '').strip()

    # Validate required fields
    if not all([address, signature, message, nonce]):
        return jsonify({'error': 'address, signature, message, and nonce are required'}), 400

    if not is_address(address):
        return jsonify({'error': 'Invalid Ethereum address format'}), 400

    address = to_checksum_address(address)

    # Validate and consume the nonce (prevents replay attacks)
    if not NonceManager.validate_and_consume_nonce(address, nonce):
        return jsonify({'error': 'Invalid, expired, or already used nonce'}), 401

    # Verify the nonce is present in the message
    if nonce not in message:
        return jsonify({'error': 'Message does not contain the expected nonce'}), 400

    # Verify the address is present in the message
    if address not in message:
        return jsonify({'error': 'Message does not contain the expected address'}), 400

    # Verify the signature
    if not SignatureVerifier.verify_signature(message, signature, address):
        return jsonify({'error': 'Signature verification failed'}), 401

    # Issue JWT token
    token = TokenManager.create_token(address)

    logger.info(f"User authenticated successfully: {address}")

    return jsonify({
        'authenticated': True,
        'address': address,
        'token': token,
        'expires_in': JWT_EXPIRATION_HOURS * 3600,
    }), 200


